import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Skeleton.module.css';

type SkeletonProps = HTMLArkProps<'div'> & {
  loading?: boolean;
  variant?: 'pulse' | 'none';
  width?: number | string;
  height?: number | string;
  boxSize?: number | string;
  borderRadius?: number | string;
};

const toCssValue = (value: number | string | undefined) =>
  typeof value === 'number' ? `${value}px` : value;

const SkeletonRoot = forwardRef<HTMLDivElement, SkeletonProps>(function SkeletonRoot(
  {
    'aria-hidden': ariaHidden,
    asChild,
    borderRadius,
    boxSize,
    className,
    height,
    loading = true,
    style,
    variant = 'pulse',
    width,
    ...props
  },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      asChild={asChild}
      data-scope="skeleton"
      data-part="root"
      data-slot="skeleton-root"
      data-state={loading ? 'loading' : 'loaded'}
      data-loading={loading ? '' : undefined}
      data-variant={variant}
      aria-hidden={ariaHidden ?? (loading ? true : undefined)}
      className={clsx(styles.root, normalizeClassName(className))}
      style={{
        width: toCssValue(width ?? boxSize),
        height: toCssValue(height ?? boxSize),
        borderRadius: toCssValue(borderRadius),
        ...style,
      }}
      {...props}
    />
  );
});

const Skeleton = Object.assign(SkeletonRoot, {
  Root: SkeletonRoot,
});

export { Skeleton };

@layer moduix.components {
  .root {
    display: block;
    width: 100%;
    overflow: hidden;
    border-radius: var(--moduix-skeleton-border-radius, var(--moduix-radius-md));

    &[data-state='loading'] {
      height: var(--moduix-skeleton-height, var(--moduix-spacing-4));
      animation: var(--moduix-skeleton-animation, var(--moduix-animation-pulse));
      background: var(
        --moduix-skeleton-bg,
        color-mix(
          in oklab,
          var(--moduix-color-muted-foreground) 18%,
          var(--moduix-color-background)
        )
      );
      color: transparent;
      pointer-events: none;
      user-select: none;

      & > * {
        visibility: hidden;
      }

      &[data-variant='none'] {
        animation: none;
      }

      @media (prefers-reduced-motion: reduce) {
        animation: none;
      }
    }
  }
}
